// RAG keyword search + memoria conversacional persistida en DB
// v2026-04-19b — mejoras para DEV:
// - resetea filtros al cambiar de marca/recurso
// - no expone links ni HTML cuando el pedido de logo sigue abierto
// - aplica filtro estricto por marca y por variantes/formatos
// - prioriza coincidencias exactas y reduce falsos positivos entre marcas

const source = $('Preparar input').first().json || {};
const httpResp = $('Cargar chunks RAG').first().json || {};
const stateRow = $('Cargar estado conversación').first().json || {};
const historyRow = $('Cargar historial conversación').first().json || {};

const chatInputOriginal = source.chatInput || '';
const conversationId = source.conversationId || '';
const userId = source.userId || '';

function safeJsonParse(value, fallback) {
  if (value == null) return fallback;
  if (typeof value === 'object') return value;
  try { return JSON.parse(value); } catch { return fallback; }
}

const previousState = safeJsonParse(stateRow.state_json, {}) || {};
let history = safeJsonParse(historyRow.history_json, []) || [];
if (!Array.isArray(history)) history = [];

function fixMojibake(value) {
  if (typeof value !== 'string') return value;
  const map = {
    'Ã¡': 'á', 'Ã©': 'é', 'Ã­': 'í', 'Ã³': 'ó', 'Ãº': 'ú',
    'Ã�': 'Á', 'Ã‰': 'É', 'Ã�': 'Í', 'Ã“': 'Ó', 'Ãš': 'Ú',
    'Ã±': 'ñ', 'Ã‘': 'Ñ', 'Ã¼': 'ü', 'Ãœ': 'Ü',
    'Â¿': '¿', 'Â¡': '¡', 'Â°': '°', 'Â´': '´',
    'â€“': '–', 'â€”': '—', 'â€œ': '“', 'â€': '”', 'â€˜': '‘', 'â€™': '’'
  };
  let out = value;
  for (const [bad, good] of Object.entries(map)) out = out.split(bad).join(good);
  return out;
}

const chatInput = fixMojibake(chatInputOriginal);

const normalize = s => fixMojibake(s || '')
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9 ]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const inputNorm = normalize(chatInput);

function getPeriod() {
  try {
    const parts = new Intl.DateTimeFormat('es-AR', {
      hour: '2-digit',
      hour12: false,
      timeZone: 'America/Argentina/Buenos_Aires'
    }).formatToParts(new Date());
    const hour = Number(parts.find(p => p.type === 'hour')?.value ?? 12);
    if (hour >= 6 && hour < 12) return 'mañana';
    if (hour >= 12 && hour < 20) return 'tarde';
    return 'noche';
  } catch {
    return 'tarde';
  }
}

const period = getPeriod();

const SALUDOS_PUROS = new Set([
  '', 'hola', 'buenas', 'buen dia', 'buenos dias', 'buenas tardes', 'buenas noches',
  'como estas', 'como va', 'que tal', 'ey', 'hey', 'que onda', 'todo bien',
  'como andas', 'que haces', 'que contas', 'como te va'
]);
const esGreeting = SALUDOS_PUROS.has(inputNorm);

const BRAND_DISPLAY = {
  personal: 'Personal',
  movil: 'Móvil',
  'móvil': 'Móvil',
  fibra: 'Fibra',
  flow: 'Flow',
  pay: 'Pay',
  tienda: 'Tienda',
  smarthome: 'Smarthome',
  tech: 'Tech'
};
const BRAND_KEYS = Object.keys(BRAND_DISPLAY);

function detectBrand(text) {
  const t = normalize(text);
  for (const key of BRAND_KEYS) {
    if (t.includes(normalize(key))) return BRAND_DISPLAY[key];
  }
  return '';
}

function detectResourceType(text) {
  const t = normalize(text);
  if (/\bisotipo\b/.test(t)) return 'isotipo';
  if (/\blogotipo\b/.test(t)) return 'logotipo';
  if (/\blogo\b/.test(t)) return 'logo';
  if (/\bmanual\b/.test(t)) return 'manual';
  if (/\btemplate\b|\bplantilla\b/.test(t)) return 'template';
  if (/\btipografia\b|\bfuente\b/.test(t)) return 'tipografía';
  if (/\bicono\b|\bícono\b|\bicon\b/.test(t)) return 'ícono';
  if (/\bvideo\b|\bspot\b/.test(t)) return 'video';
  if (/\bimagen\b|\bfondo\b/.test(t)) return 'imagen';
  return '';
}

function detectFormat(text) {
  const t = normalize(text);
  if (/\bsvg\b/.test(t)) return 'svg';
  if (/\bpng\b/.test(t)) return 'png';
  if (/\bjpe?g\b/.test(t)) return 'jpg';
  if (/\bpdf\b/.test(t)) return 'pdf';
  if (/\bai\b|\billustrator\b/.test(t)) return 'ai';
  if (/\beps\b/.test(t)) return 'eps';
  if (/\bdocx\b|\bword\b/.test(t)) return 'docx';
  if (/\bpptx\b|\bpowerpoint\b/.test(t)) return 'pptx';
  if (/\bzip\b/.test(t)) return 'zip';
  if (/\bttf\b/.test(t)) return 'ttf';
  if (/\botf\b/.test(t)) return 'otf';
  if (/\bmp4\b/.test(t)) return 'mp4';
  if (/\bmov\b/.test(t)) return 'mov';
  return '';
}

function detectColor(text) {
  const t = normalize(text);
  if (/\bblanco\b/.test(t)) return 'blanco';
  if (/\bnegro\b/.test(t)) return 'negro';
  if (/\bcolor\b/.test(t)) return 'color';
  return '';
}

function detectBackground(text) {
  const t = normalize(text);
  if (/\bfondo marca\b/.test(t)) return 'fondo marca';
  if (/\btransparente\b|\bfondo transparente\b/.test(t)) return 'fondo transparente';
  if (/\bfondo negro\b/.test(t)) return 'fondo negro';
  if (/\bfondo blanco\b/.test(t)) return 'fondo blanco';
  if (/\bfondo oscuro\b/.test(t)) return 'fondo oscuro';
  if (/\bfondo claro\b/.test(t)) return 'fondo claro';
  return '';
}

function detectUseCase(text) {
  const t = normalize(text);
  if (/\bweb\b|\bpantalla\b|\bdigital\b/.test(t)) return 'web';
  if (/\bpresentacion\b|\bpowerpoint\b|\bppt\b/.test(t)) return 'presentación';
  if (/\bimpresion\b|\bimprenta\b|\bimprimir\b/.test(t)) return 'impresión';
  if (/\bedicion\b|\beditar\b|\billustrator\b|\bdiseño\b|\bdiseno\b/.test(t)) return 'edición';
  if (/\bmail\b|\bemail\b|\bcorreo\b/.test(t)) return 'mail';
  if (/\bvideo\b/.test(t)) return 'video';
  return '';
}

function capitalizeResourceType(rt) {
  const map = {
    logo: 'logo',
    logotipo: 'logotipo',
    isotipo: 'isotipo',
    manual: 'manual',
    template: 'template',
    'tipografía': 'tipografía',
    'ícono': 'ícono',
    video: 'video',
    imagen: 'imagen'
  };
  return map[rt] || 'recurso';
}

function hasNewIntent(text) {
  const t = normalize(text);
  return /\bnecesito\b|\bquiero\b|\bpasame\b|\bmandame\b|\bbusco\b|\bdame\b|\bmostrar\b|\bmostrame\b|\bver\b/.test(t);
}

const explicitBrand = detectBrand(chatInput);
const explicitResourceType = detectResourceType(chatInput);
const explicitFormat = detectFormat(chatInput);
const explicitColor = detectColor(chatInput);
const explicitBackground = detectBackground(chatInput);
const explicitUseCase = detectUseCase(chatInput);

let active_brand = explicitBrand || previousState.active_brand || '';
let active_resource_type = explicitResourceType || previousState.active_resource_type || '';
let active_format = explicitFormat || previousState.active_format || '';
let active_color = explicitColor || previousState.active_color || '';
let active_background = explicitBackground || previousState.active_background || '';
let active_use_case = explicitUseCase || previousState.active_use_case || '';

// Si cambia explícitamente de marca o de tipo de recurso en un nuevo pedido, resetear filtros dependientes.
const explicitBrandChanged = !!(explicitBrand && previousState.active_brand && explicitBrand !== previousState.active_brand);
const explicitResourceChanged = !!(explicitResourceType && previousState.active_resource_type && explicitResourceType !== previousState.active_resource_type);
// FIX: el cambio explícito de marca o de tipo de recurso ya es señal suficiente
// de pedido nuevo. Exigir además un verbo de intención ("necesito", "pasame")
// hacía que el caso documentado "logo de Personal" NO reseteara los filtros.
if (explicitBrandChanged || explicitResourceChanged) {
  active_format = explicitFormat || '';
  active_color = explicitColor || '';
  active_background = explicitBackground || '';
  active_use_case = explicitUseCase || '';
}

// Completar marca/recurso desde historial solo si no vino explícito nada nuevo.
if (!active_brand) {
  for (let i = history.length - 1; i >= 0; i--) {
    const row = history[i] || {};
    if ((row.role || '').toLowerCase() !== 'user') continue;
    const found = detectBrand(row.content || '');
    if (found) { active_brand = found; break; }
  }
}
if (!active_resource_type) {
  for (let i = history.length - 1; i >= 0; i--) {
    const row = history[i] || {};
    if ((row.role || '').toLowerCase() !== 'user') continue;
    const found = detectResourceType(row.content || '');
    if (found) { active_resource_type = found; break; }
  }
}
if (!active_resource_type && /\blogo\b/.test(inputNorm)) active_resource_type = 'logo';

const isLogoRequest = ['logo', 'logotipo', 'isotipo'].includes(active_resource_type) || /\blogo\b|\blogotipo\b|\bisotipo\b/.test(inputNorm);

let pending_question = '';
let is_request_fully_filtered = false;

if (isLogoRequest) {
  const hasVisual = !!(active_color || active_background);
  const hasFormatOrUse = !!(active_format || active_use_case);
  is_request_fully_filtered = !!(active_brand && (hasVisual || hasFormatOrUse));

  if (!active_brand) pending_question = 'brand';
  else if (!hasVisual) pending_question = 'visual_variant';
  else if (!hasFormatOrUse) pending_question = 'format_or_use';
} else {
  is_request_fully_filtered = !!active_brand || !!inputNorm;
}

// Si saludo puro, devolver antes de cargar RAG pesado.
const historyText = history
  .slice(-8)
  .map(row => `${(row.role || '').toLowerCase() === 'assistant' ? 'Asistente' : 'Usuario'}: ${fixMojibake(row.content || '')}`)
  .join('\n');

const conversationStateSummary = [
  `conversationId: ${conversationId || ''}`,
  `marca_activa: ${active_brand || '(vacía)'}`,
  `recurso_activo: ${active_resource_type || '(vacío)'}`,
  `formato_activo: ${active_format || '(vacío)'}`,
  `color_activo: ${active_color || '(vacío)'}`,
  `fondo_activo: ${active_background || '(vacío)'}`,
  `uso_activo: ${active_use_case || '(vacío)'}`,
  `pending_question: ${pending_question || '(ninguna)'}`,
  `request_fully_filtered: ${is_request_fully_filtered ? 'true' : 'false'}`
].join('\n');

if (esGreeting) {
  return [{
    json: {
      chatInput,
      conversationId,
      userId,
      contexto: '',
      chunks_encontrados: 0,
      es_greeting: true,
      es_casual: true,
      period,
      historyText,
      conversationStateSummary,
      active_brand,
      active_resource_type,
      active_format,
      active_color,
      active_background,
      active_use_case,
      pending_question,
      is_request_fully_filtered,
      last_matching_chunk_ids: [],
      intro_text: '',
      links_descarga_lookup: {},
      usar_html_descarga: false
    }
  }];
}

let rawText = '';
try {
  rawText = httpResp.data || httpResp.body || httpResp.response || httpResp.text || '';
  if (typeof rawText !== 'string') rawText = JSON.stringify(rawText);
  rawText = fixMojibake(rawText);
} catch (e) {
  return [{ json: {
    chatInput, conversationId, userId, contexto: '', chunks_encontrados: 0,
    es_greeting: false, es_casual: false, period, historyText, conversationStateSummary,
    active_brand, active_resource_type, active_format, active_color, active_background,
    active_use_case, pending_question, is_request_fully_filtered, last_matching_chunk_ids: [],
    intro_text: '', links_descarga_lookup: {}, usar_html_descarga: false,
    error: 'No se pudo leer el JSONL: ' + e.message
  }}];
}

const chunks = [];
for (const line of String(rawText).split('\n')) {
  const l = line.trim();
  if (!l) continue;
  try { chunks.push(JSON.parse(l)); } catch {}
}

if (chunks.length === 0) {
  return [{ json: {
    chatInput, conversationId, userId, contexto: '', chunks_encontrados: 0,
    es_greeting: false, es_casual: false, period, historyText, conversationStateSummary,
    active_brand, active_resource_type, active_format, active_color, active_background,
    active_use_case, pending_question, is_request_fully_filtered, last_matching_chunk_ids: [],
    intro_text: '', links_descarga_lookup: {}, usar_html_descarga: false,
    error: 'No se pudieron parsear chunks'
  }}];
}

const STOPWORDS = new Set([
  'que','para','como','con','los','las','una','uno','del','por','son','hay',
  'esto','esta','este','ese','esa','pero','todo','todos','todas','cuando',
  'tiene','tengo','puedo','poder','quiero','necesito','busco','donde',
  'cuales','cuantos','algun','alguna','tienen','cual','dame','dime',
  'estan','existe','existen','podria','pasame','mandame','dar','ver',
  'archivo','archivos','descargar','descarga'
]);

let tokens = inputNorm
  .split(/\s+/)
  .filter(w => w.length >= 2 && !STOPWORDS.has(w));

const tokenSet = new Set(tokens);
if (tokenSet.has('logo')) tokenSet.add('logotipo');
if (tokenSet.has('logotipo')) tokenSet.add('logo');
if (tokenSet.has('simbolo')) tokenSet.add('isotipo');
if (tokenSet.has('editable')) tokenSet.add('ai');
if (tokenSet.has('illustrator')) tokenSet.add('ai');
if (tokenSet.has('vectorial')) tokenSet.add('svg');
if (tokenSet.has('transparente')) tokenSet.add('png');
if (active_brand) tokenSet.add(normalize(active_brand));
if (active_resource_type) tokenSet.add(normalize(active_resource_type));
if (active_format) tokenSet.add(normalize(active_format));
if (active_color) tokenSet.add(normalize(active_color));
if (active_background) tokenSet.add(normalize(active_background));
tokens = Array.from(tokenSet);

function safeRe(token) {
  return token.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function detectChunkBrand(chunk) {
  const meta = chunk.metadata || {};

  // 1) La página es la fuente más confiable: en Ecosistema, la página ES la marca.
  const byPage = detectBrand(meta.pagina || '');
  if (byPage) return byPage;

  // 2) Metadata estructurada (sin texto libre).
  const metaText = [
    meta.ubicacion_chatbot,
    meta.nombre_recurso,
    meta.area_principal,
    meta.subarea_1,
    meta.subarea_2,
    meta.seccion
  ].filter(Boolean).join(' ');
  const byMeta = detectBrand(metaText);
  if (byMeta) return byMeta;

  // 3) Texto libre, PERO removiendo URLs y HTML primero:
  //    el dominio comustock.personal.com.ar contiene "personal" y contaminaba
  //    la detección de TODOS los chunks hacia la marca Personal.
  const textoLimpio = String(chunk.texto || '')
    .replace(/https?:\/\/[^\s"'<>]+/g, ' ')
    .replace(/<[^>]+>/g, ' ');
  return detectBrand(textoLimpio);
}

function detectChunkResourceType(chunk) {
  const meta = chunk.metadata || {};
  const text = [meta.tipo_activo, meta.nombre_recurso, chunk.texto].filter(Boolean).join(' ');
  return detectResourceType(text);
}

function linkMatchesFilters(link) {
  const haystack = normalize([
    link.formato || '',
    link.filename || '',
    link.label_visible || ''
  ].join(' '));

  // El formato puede venir del campo formato, del filename o del label.
  if (active_format && !haystack.includes(normalize(active_format))) return false;

  // Color y fondo se testean SOLO sobre el label estructurado
  // ("Isotipo Flow Negro sobre fondo blanco en AI"): el filename contamina
  // (flow-iso-negro.ai es la variante "color, fondo negro").
  const label = normalize(link.label_visible || '');

  // Para el COLOR, remover primero las frases "fondo <palabra>" del label:
  // si no, "Negro sobre fondo blanco" matchea color=blanco.
  const labelSinFondo = label.replace(/fondo\s+\S+/g, ' ');

  if (active_color === 'blanco' && !/\bblanco\b|\bwhite\b/.test(labelSinFondo)) return false;
  if (active_color === 'negro' && !/\bnegro\b|\bblack\b/.test(labelSinFondo)) return false;
  if (active_color === 'color' && !/\bcolor\b/.test(labelSinFondo)) return false;

  // El FONDO se testea sobre el label completo, exigiendo la frase con "fondo".
  if (active_background) {
    const bg = normalize(active_background);
    if (bg === 'fondo marca' && !/\bfondo marca\b/.test(label)) return false;
    if (bg === 'fondo transparente' && !/\bfondo transparente\b|\btransparente\b/.test(label)) return false;
    if (bg === 'fondo negro' && !/\bfondo negro\b/.test(label)) return false;
    if (bg === 'fondo blanco' && !/\bfondo blanco\b/.test(label)) return false;
    if (bg === 'fondo oscuro' && !/\bfondo oscuro\b/.test(label)) return false;
    if (bg === 'fondo claro' && !/\bfondo claro\b/.test(label)) return false;
  }

  return true;
}

const scored = chunks.map(chunk => {
  const meta = chunk.metadata || {};
  const textoNorm = normalize(chunk.texto || '');
  const extraNorm = normalize([
    meta.palabras_clave,
    meta.nombre_recurso,
    meta.area_principal,
    meta.subarea_1,
    meta.subarea_2,
    meta.pagina,
    meta.seccion,
    meta.ubicacion_chatbot,
    meta.tipo_activo,
    meta.formatos_disponibles,
    meta.grupo_modal,
    meta.archivo_base_descarga,
    Array.isArray(meta.links_descarga) ? meta.links_descarga.map(l => [l.formato, l.filename, l.label_visible].join(' ')).join(' ') : ''
  ].filter(Boolean).join(' '));

  let score = 0;

  for (const token of tokens) {
    const wordRe = new RegExp('\\b' + safeRe(token) + '\\b', 'g');
    const m1 = textoNorm.match(wordRe);
    if (m1) score += m1.length * 2;
    else if (textoNorm.includes(token)) score += 1;

    const m2 = extraNorm.match(wordRe);
    if (m2) score += m2.length * 5;
    else if (extraNorm.includes(token)) score += 2;
  }

  const chunkBrand = detectChunkBrand(chunk);
  const chunkResourceType = detectChunkResourceType(chunk);
  const hasDownload = !!(meta.links_descarga_html || meta.respuesta_html_no_modificar || meta.links_descarga?.length);

  let exclude = false;

  if (active_brand) {
    if (chunkBrand === active_brand) score += 24;
    else if (chunkBrand && hasDownload) exclude = true;
    else if (chunkBrand) score -= 60;
  }

  if (active_resource_type && chunkResourceType === active_resource_type) score += 12;

  if (active_format && extraNorm.includes(normalize(active_format))) score += 8;
  if (active_color && extraNorm.includes(normalize(active_color))) score += 7;
  if (active_background && extraNorm.includes(normalize(active_background))) score += 7;
  if (active_use_case && extraNorm.includes(normalize(active_use_case))) score += 5;

  if (chunk.tipo_chunk === 'descargable') score += 5;
  if (chunk.tipo_chunk === 'recurso') score += 5;
  if (chunk.tipo_chunk === 'pagina') score += 1;
  if (chunk.tipo_chunk === 'asistente') score += 1;

  if (hasDownload) score += 4;

  // Si ya está filtrado un pedido de logo, priorizar chunks con links que además cumplan el filtro.
  if (isLogoRequest && is_request_fully_filtered && Array.isArray(meta.links_descarga) && meta.links_descarga.length) {
    const matchingLinks = meta.links_descarga.filter(linkMatchesFilters);
    if (matchingLinks.length) score += 30;
    else if (hasDownload) exclude = true;
  }

  return { chunk, score, exclude };
});

const TOP_K = 10;
const MAX_CHARS = 15000;

const topScored = scored
  .filter(s => !s.exclude && s.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, TOP_K);

const topChunks = topScored.map(s => s.chunk);
const last_matching_chunk_ids = topChunks.map(c => c.id).filter(Boolean);

const linksLookup = {};
const linksValidos = [];

for (const chunk of topChunks) {
  const meta = chunk.metadata || {};
  const links = Array.isArray(meta.links_descarga) ? meta.links_descarga : [];
  for (const link of links) {
    if (!link || !link.filename || !link.url) continue;
    if (!/^https:\/\/comustock\.personal\.com\.ar\/content\//.test(link.url)) continue;
    if (isLogoRequest && is_request_fully_filtered && !linkMatchesFilters(link)) continue;

    linksLookup[link.filename] = link.url;
    linksValidos.push({
      id: chunk.id || '',
      pagina: meta.pagina || '',
      recurso: meta.nombre_recurso || '',
      formato: link.formato || '',
      filename: link.filename,
      url: link.url,
      label_visible: link.label_visible || ''
    });
  }
}

function stripHtmlFromIndexableText(text) {
  return String(text || '')
    .replace(/Respuesta HTML sugerida:[\s\S]*/i, '')
    .replace(/HTML exacto para respuesta:[\s\S]*/i, '')
    .trim();
}

function buildContextEntry(chunk, index) {
  const meta = chunk.metadata || {};
  const ubicacion = meta.ubicacion_chatbot
    || [meta.seccion, meta.pagina, meta.area_principal, meta.subarea_1, meta.subarea_2].filter(Boolean).join(' > ');

  const lines = [
    `CHUNK ${index + 1}`,
    `ID: ${chunk.id || ''}`,
    `TIPO: ${chunk.tipo_chunk || ''}`,
    `UBICACION: ${ubicacion || ''}`,
    `SECCION: ${meta.seccion || ''}`,
    `PAGINA: ${meta.pagina || ''}`,
    `AREA: ${meta.area_principal || ''}`,
    `SUBAREA_1: ${meta.subarea_1 || ''}`,
    `SUBAREA_2: ${meta.subarea_2 || ''}`,
    `RECURSO: ${meta.nombre_recurso || ''}`,
    `TIPO_ACTIVO: ${meta.tipo_activo || ''}`,
    `FORMATOS: ${meta.formatos_disponibles || ''}`,
    `DESCRIPCION: ${meta.descripcion_clara || ''}`
  ];

  const hideDownloadsForClarification = isLogoRequest && !is_request_fully_filtered;
  const links = Array.isArray(meta.links_descarga) ? meta.links_descarga : [];
  const cleanLinks = links
    .filter(l => l && /^https:\/\/comustock\.personal\.com\.ar\/content\//.test(l.url || ''))
    .filter(l => !isLogoRequest || !is_request_fully_filtered || linkMatchesFilters(l))
    .map(l => ({
      formato: l.formato || '',
      filename: l.filename || '',
      url: l.url || '',
      label_visible: l.label_visible || ''
    }));

  if (!hideDownloadsForClarification && cleanLinks.length) {
    lines.push('LINKS_DESCARGA_VALIDOS_JSON:');
    lines.push(JSON.stringify(cleanLinks));
  }

  const htmlExacto = meta.respuesta_html_no_modificar || meta.links_descarga_html || '';
  if (!hideDownloadsForClarification && htmlExacto) {
    lines.push('HTML_DESCARGA_EXACTO_NO_MODIFICAR:');
    lines.push(htmlExacto);
    lines.push('FIN_HTML_DESCARGA_EXACTO_NO_MODIFICAR');
  }

  const textoIndexable = stripHtmlFromIndexableText(chunk.texto || '');
  if (textoIndexable) lines.push(`TEXTO_INDEXABLE: ${textoIndexable.slice(0, 700)}`);

  return lines.filter(Boolean).join('\n');
}

let contexto = '';
if (topChunks.length > 0) {
  const partes = [];
  let total = 0;
  for (let i = 0; i < topChunks.length; i++) {
    const parte = buildContextEntry(topChunks[i], i);
    if (!parte) continue;
    if (total + parte.length > MAX_CHARS) break;
    partes.push(parte);
    total += parte.length;
  }
  contexto = partes.join('\n\n---\n\n');

  // FIX "pregunta + no encontré": cuando el pedido está abierto, los links se
  // ocultan A PROPÓSITO. Avisarle al LLM de forma explícita que SÍ hay
  // coincidencias, para que no infiera "sin links = no encontré información".
  if (isLogoRequest && !is_request_fully_filtered) {
    contexto = [
      `AVISO_PEDIDO_ABIERTO: SÍ HAY ${topChunks.length} COINCIDENCIAS EN COMUSTOCK para este pedido.`,
      `Los links de descarga están ocultos a propósito hasta que el usuario confirme el filtro (color, formato o uso).`,
      `PROHIBIDO decir que no encontraste información. PROHIBIDO mencionar el email de soporte.`,
      `Tu única tarea en este turno: hacer UNA pregunta breve para completar el filtro.`,
      '',
      contexto
    ].join('\n');
  }
}

let intro_text = '';
const hasDownloadContext = linksValidos.length > 0 || /HTML_DESCARGA_EXACTO_NO_MODIFICAR/.test(contexto);
if (hasDownloadContext) {
  if (active_brand && ['logo', 'logotipo', 'isotipo'].includes(active_resource_type)) {
    intro_text = `Descargando ${capitalizeResourceType(active_resource_type)} de ${active_brand}.`;
  } else if (active_brand && active_resource_type) {
    intro_text = `Descargando ${capitalizeResourceType(active_resource_type)} de ${active_brand}.`;
  } else if (active_brand) {
    intro_text = `Descargando recursos de ${active_brand}.`;
  } else if (active_resource_type) {
    intro_text = `Descargando ${capitalizeResourceType(active_resource_type)}.`;
  } else {
    intro_text = 'Descargando recursos.';
  }
}

return [{
  json: {
    chatInput,
    conversationId,
    userId,
    contexto,
    chunks_encontrados: topChunks.length,
    es_greeting: false,
    es_casual: false,
    period,
    historyText,
    conversationStateSummary,
    active_brand,
    active_resource_type,
    active_format,
    active_color,
    active_background,
    active_use_case,
    pending_question,
    is_request_fully_filtered,
    last_matching_chunk_ids,
    intro_text,
    links_descarga_lookup: linksLookup,
    links_descarga_validos: linksValidos,
    usar_html_descarga: hasDownloadContext
  }
}];

