parameters.jsCode:
// Sanear salida final del LLM
// Corrige fences, mojibake, xmlns, hrefs y ajusta labels visibles para descargables.

const current = $input.first().json || {};
const data = $('Buscar en RAG').first().json || {};
const lookup = data.links_descarga_lookup || {};
const activeBrand = data.active_brand || '';
const activeResourceType = data.active_resource_type || '';
const introText = data.intro_text || '';

function fixMojibake(value) {
  if (typeof value !== 'string') return value;
  const map = {
    'Ã¡': 'á', 'Ã©': 'é', 'Ã­': 'í', 'Ã³': 'ó', 'Ãº': 'ú',
    'Ã�': 'Á', 'Ã‰': 'É', 'Ã�': 'Í', 'Ã“': 'Ó', 'Ãš': 'Ú',
    'Ã±': 'ñ', 'Ã‘': 'Ñ', 'Ã¼': 'ü', 'Ãœ': 'Ü',
    'Â¿': '¿', 'Â¡': '¡', 'Â°': '°',
    'â€“': '–', 'â€”': '—', 'â€œ': '“', 'â€': '”', 'â€˜': '‘', 'â€™': '’'
  };
  let out = value;
  for (const [bad, good] of Object.entries(map)) out = out.split(bad).join(good);
  return out;
}

function normalize(s) {
  return fixMojibake(s || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const BRAND_DISPLAY = {
  personal: 'Personal',
  movil: 'Móvil',
  'móvil': 'Móvil',
  fibra: 'Fibra',
  flow: 'Flow',
  pay: 'Pay',
  tienda: 'Tienda',
  smarthome: 'Smarthome',
  tech: 'Tech'
};
const BRAND_KEYS = Object.keys(BRAND_DISPLAY);

function detectBrand(text) {
  const t = normalize(text);
  for (const key of BRAND_KEYS) {
    if (t.includes(normalize(key))) return BRAND_DISPLAY[key];
  }
  return activeBrand || '';
}

function detectResourceType(text) {
  const t = normalize(text);
  if (/\bisotipo\b/.test(t)) return 'Isotipo';
  if (/\blogotipo\b/.test(t)) return 'Logotipo';
  if (/\blogo\b/.test(t)) return 'Logo';
  if (/\bmanual\b/.test(t)) return 'Manual';
  if (/\btemplate\b|\bplantilla\b/.test(t)) return 'Template';
  if (/\bicono\b|\bícono\b|\bicon\b/.test(t)) return 'Ícono';
  if (/\bvideo\b|\bspot\b/.test(t)) return 'Video';
  if (/\bimagen\b|\bfondo\b/.test(t)) return 'Imagen';
  if (activeResourceType) {
    const map = {logo:'Logo', logotipo:'Logotipo', isotipo:'Isotipo', manual:'Manual', template:'Template', 'ícono':'Ícono', video:'Video', imagen:'Imagen'};
    return map[activeResourceType] || 'Recurso';
  }
  return 'Recurso';
}

function detectColor(text) {
  const t = normalize(text);
  if (/\bblanco\b/.test(t)) return 'blanco';
  if (/\bnegro\b/.test(t)) return 'negro';
  if (/\bcolor\b/.test(t)) return 'color';
  return '';
}

function detectBackground(text) {
  const t = normalize(text);
  if (/\bfondo marca\b/.test(t)) return 'Fondo marca';
  if (/\btransparente\b|\bfondo transparente\b/.test(t)) return 'Fondo transparente';
  if (/\bfondo negro\b/.test(t)) return 'Fondo negro';
  if (/\bfondo blanco\b/.test(t)) return 'Fondo blanco';
  if (/\bfondo oscuro\b/.test(t)) return 'Fondo oscuro';
  if (/\bfondo claro\b/.test(t)) return 'Fondo claro';
  return '';
}

function detectFormat(text) {
  const t = normalize(text);
  if (/\bsvg\b/.test(t)) return 'SVG';
  if (/\bpng\b/.test(t)) return 'PNG';
  if (/\bjpe?g\b/.test(t)) return 'JPG';
  if (/\bpdf\b/.test(t)) return 'PDF';
  if (/\bai\b|\billustrator\b/.test(t)) return 'AI';
  if (/\beps\b/.test(t)) return 'EPS';
  if (/\bdocx\b|\bword\b/.test(t)) return 'DOCX';
  if (/\bpptx\b|\bpowerpoint\b/.test(t)) return 'PPTX';
  if (/\bzip\b/.test(t)) return 'ZIP';
  if (/\bttf\b/.test(t)) return 'TTF';
  if (/\botf\b/.test(t)) return 'OTF';
  if (/\bmp4\b/.test(t)) return 'MP4';
  if (/\bmov\b/.test(t)) return 'MOV';
  return '';
}

function rewriteDownloadLabel(raw) {
  const text = fixMojibake(String(raw || '')).replace(/\s+/g, ' ').trim();
  if (!text) return raw;
  if (/<span>/i.test(text)) return raw;

  const brand = detectBrand(text) || activeBrand || 'Recurso';
  const resourceType = detectResourceType(text);
  const color = detectColor(text);
  const background = detectBackground(text);
  const format = detectFormat(text);

  const left = brand;
  const parts = [];
  let resourcePart = resourceType;
  if (color) resourcePart += ` ${color}`;
  parts.push(resourcePart);
  if (background) parts.push(background);
  if (format) parts.push(format);

  return `${left}: <span>${parts.join(' · ')}</span>`;
}

let output = String(current.output ?? current.text ?? current.response ?? '').trim();
output = fixMojibake(output);

output = output
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

output = output
  .replace(/xmlns=\"www\.w3\.org\/2000\/svg\"/g, 'xmlns=\"http://www.w3.org/2000/svg\"')
  .replace(/xmlns='www\.w3\.org\/2000\/svg'/g, "xmlns='http://www.w3.org/2000/svg'");

output = output.replace(/href=\"(comustock\.personal\.com\.ar\/content\/[^\"]+)\"/g, 'href=\"https://$1\"');
output = output.replace(/href='(comustock\.personal\.com\.ar\/content\/[^']+)'/g, "href='https://$1'");
output = output.replace(/href=\"(\/content\/[^\"]+)\"/g, 'href=\"https://comustock.personal.com.ar$1\"');
output = output.replace(/href='(\/content\/[^']+)'/g, "href='https://comustock.personal.com.ar$1'");

function replaceBrokenHrefWithDownloadLookup(html) {
  html = html.replace(/(<a\b[^>]*?\bhref=[\"'])(?:https?:\/\/)?comustock\.personal\.com\.ar\/?([\"'][^>]*?\bdownload=[\"']([^\"']+)[\"'][^>]*>)/gi,
    (match, before, after, filename) => {
      const url = lookup[filename];
      return url ? `${before}${url}${after}` : match;
    }
  );
  html = html.replace(/(<a\b[^>]*?\bdownload=[\"']([^\"']+)[\"'][^>]*?\bhref=[\"'])(?:https?:\/\/)?comustock\.personal\.com\.ar\/?([\"'][^>]*>)/gi,
    (match, before, filename, after) => {
      const url = lookup[filename];
      return url ? `${before}${url}${after}` : match;
    }
  );
  return html;
}

output = replaceBrokenHrefWithDownloadLookup(output);

output = output.replace(/href=\"(?:https?:\/\/)?comustock\.personal\.com\.ar\/?\"/g, 'href=\"#\" data-link-invalido=\"true\"');
output = output.replace(/href='(?:https?:\/\/)?comustock\.personal\.com\.ar\/?'/g, "href='#' data-link-invalido='true'");

output = output.replace(/<a\b([^>]*\bhref=[\"']https:\/\/comustock\.personal\.com\.ar\/content\/[^\"']+[\"'][^>]*)>/gi, (match, attrs) => {
  let next = attrs;
  if (!/\btarget=/.test(next)) next += ' target=\"_blank\"';
  if (!/\brel=/.test(next)) next += ' rel=\"noopener noreferrer\"';
  return `<a${next}>`;
});

// Reescribir labels visibles
output = output.replace(/<span class=\"comustock-download-link__label\">([\s\S]*?)<\/span>/gi, (match, inner) => {
  const label = rewriteDownloadLabel(inner.replace(/<[^>]+>/g, ' ').trim());
  return `<span class="comustock-download-link__label">${label}</span>`;
});

// Agregar línea introductoria si hay descargables y no existe ya
const hasDownloadMarkup = /comustock-download-card|comustock-downloads|comustock-download-link/.test(output);
const hasIntro = /class=["']comustock-download-intro["']/.test(output);
if (hasDownloadMarkup && !hasIntro && introText) {
  output = `<p class="comustock-download-intro">${introText}</p>\n${output}`;
}

return [{
  json: {
    output,
    html_render: true,
    links_descarga_lookup_count: Object.keys(lookup).length
  }
}];

