SELECT COALESCE((
  SELECT json_agg(h ORDER BY h.created_at)
  FROM (
    SELECT role, content, created_at
    FROM cs_chat_messages
    WHERE conversation_id = $1
    ORDER BY created_at DESC
    LIMIT 12
  ) h
), '[]'::json) AS history_json;

INSERT INTO cs_chat_messages (conversation_id, role, content, metadata_json, created_at)
VALUES ($1, 'user', $2, $3::jsonb, NOW())
RETURNING id, conversation_id, role, created_at;

INSERT INTO cs_chat_messages (conversation_id, role, content, metadata_json, created_at)
VALUES ($1, 'assistant', $2, $3::jsonb, NOW())
RETURNING id, conversation_id, role, created_at;
